internal class TmslException: UniffiException {
    TmslException(string message): base(message) {}

    // Each variant is a nested class
    // Flat enums carries a string error message, so no special implementation is necessary.
    
    public class Io: TmslException {
        public Io(string message): base(message) {}
    }
    
    public class InvalidMagic: TmslException {
        public InvalidMagic(string message): base(message) {}
    }
    
    public class InvalidVersion: TmslException {
        public InvalidVersion(string message): base(message) {}
    }
    
    public class MmapException: TmslException {
        public MmapException(string message): base(message) {}
    }
    
    public class CompressionException: TmslException {
        public CompressionException(string message): base(message) {}
    }
    
    public class DecompressionException: TmslException {
        public DecompressionException(string message): base(message) {}
    }
    
    public class InvalidData: TmslException {
        public InvalidData(string message): base(message) {}
    }
    
    public class NotFound: TmslException {
        public NotFound(string message): base(message) {}
    }
    
    public class Expired: TmslException {
        public Expired(string message): base(message) {}
    }
    
    public class AlreadyExists: TmslException {
        public AlreadyExists(string message): base(message) {}
    }
    
    public class SegmentFull: TmslException {
        public SegmentFull(string message): base(message) {}
    }
    
    public class QueueAlreadyOpen: TmslException {
        public QueueAlreadyOpen(string message): base(message) {}
    }
    
    public class QueueNotOpen: TmslException {
        public QueueNotOpen(string message): base(message) {}
    }
    
    public class ConsumerGroupNotFound: TmslException {
        public ConsumerGroupNotFound(string message): base(message) {}
    }
    
    public class ConsumerGroupExists: TmslException {
        public ConsumerGroupExists(string message): base(message) {}
    }
    
    public class QueueClosed: TmslException {
        public QueueClosed(string message): base(message) {}
    }
    
    public class PendingFull: TmslException {
        public PendingFull(string message): base(message) {}
    }
    
    public class StoreClosed: TmslException {
        public StoreClosed(string message): base(message) {}
    }
    
    public class DatasetClosed: TmslException {
        public DatasetClosed(string message): base(message) {}
    }
    
    public class QueueBridgeClosed: TmslException {
        public QueueBridgeClosed(string message): base(message) {}
    }
    
    public class IteratorExhausted: TmslException {
        public IteratorExhausted(string message): base(message) {}
    }
    
}

class FfiConverterTypeTmslError : FfiConverterRustBuffer<TmslException>, CallStatusErrorHandler<TmslException> {
    public static FfiConverterTypeTmslError INSTANCE = new FfiConverterTypeTmslError();

    public override TmslException Read(BigEndianStream stream) {
        var value = stream.ReadInt();
